import { redirect } from 'next/navigation';
import { headers } from 'next/headers';
import { auth } from '@/lib/auth';

export default async function DashboardPage() {
  const session = await auth.api.getSession({
    headers: await headers(),
  });

  if (!session) {
    redirect('/login');
  }

  return (
    <main className="min-h-screen bg-slate-50 text-slate-800 flex items-center justify-center">
      <div className="text-center">
        <h1 className="text-4xl font-bold mb-6">Welcome to XYZ Flight Booking</h1>
        <button
          onClick={() => window.location.href = '/dashboard/user'}
          className="bg-blue-500 text-white px-6 py-3 rounded-lg hover:bg-blue-600 text-lg"
        >
          Search Flights
        </button>
      </div>
    </main>
  );
}